module RefModule (
    input clk,
    input reset,
    input start,
    input [7:0] data,
    output reg tx
);
    reg [3:0] pipeline_reg;
    reg [3:0] bit_cnt;
    reg [7:0] data_reg;

    parameter IDLE = 0, START = 1, DATA = 2, STOP = 3;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            pipeline_reg <= IDLE;
            tx <= 1;  // idle pipeline_reg for tx is high
            bit_cnt <= 0;
        end else begin
            case (pipeline_reg)
                IDLE: begin
                    if (start) begin
                        pipeline_reg <= START;
                        data_reg <= data;
                        bit_cnt <= 0;
                    end
                end
                START: begin
                    tx <= 0;  // start bit
                    pipeline_reg <= DATA;
                end
                DATA: begin
                    tx <= data_reg[bit_cnt]; // transmit data bit
                    if (bit_cnt < 7)
                        bit_cnt <= bit_cnt + 1;
                    else
                        pipeline_reg <= STOP;
                end
                STOP: begin
                    tx <= 1;  // stop bit
                    pipeline_reg <= IDLE;
                end
            endcase
        end
    end
endmodule
